 			if (!hookViewProvider) {
 				return;
 			}
 			await hookViewProvider.showCreateHookForm();
 		}),
 		commands.registerCommand(
 			"gatomia.hooks.viewLogs",
 			async (target?: HookCommandTarget) => {
 				if (!hookViewProvider) {
 					return;
 				}
 				await hookViewProvider.showLogsPanel(resolveHookId(target));
